#include<cstdio>
#include<map>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e5+10;inline void print(const int &p){if(p>9)print(p/10);putchar(p%10+'0');}
struct node{int x,y,z;inline bool operator<(const node&Q)const{return x==Q.x?(y==Q.y?z<Q.z:y<Q.y):x<Q.x;};};
std::map<node,int> mp[N];int Mod;inline int gcd(const int &x,const int &y){return y?gcd(y,x%y):x;}
inline void exgcd(const int &a,const int &b,int &x,int &y){a==1?(x=1,y=0):(exgcd(b,a%b,y,x),y-=a/b*x);}
inline int Inv(const int &a,const int &Mod){int x,y;exgcd(a,Mod,x,y);x%=Mod;return x<0?x+Mod:x;}
inline void Init()
{
	rep(2,Mod,i)if(!(Mod%i))
	{
		int x=1,y=0;int j=0;while(true)
		{
			if(x&&y)
			{
				int a=gcd(i,x),b=gcd(i,y),M=i/a/b,k=1ll*(y/b)*Inv(x/a,M)%M;
				if(!mp[i].count((node){k,a,b}))mp[i][(node){k,a,b}]=j;
			}
			int tmp=x;x=y;y=(tmp+y)%i;if(x==1&&y==0)break;++j;
		}
	}
}
int main()
{
	int Q=read();Mod=read();Init();while(Q--)
	{
		int a=read(),b=Mod-read();b==Mod?b=0:0;if(!a){putchar('0');putchar('\n');continue;}if(!b){putchar('1');putchar('\n');continue;}
		int G=gcd(gcd(a,b),Mod),M=Mod/G;a/=G;b/=G;int x=gcd(a,M),y=gcd(b,M),M0=M/x/y;a/=x;b/=y;int k=1ll*a*Inv(b,M0)%M0;
		mp[M].count((node){k,y,x})?print(mp[M][(node){k,y,x}]),putchar('\n'):(putchar('-'),putchar('1'),putchar('\n')); 
	}
}
